import jsonimport urllib.requestfrom prettytable import PrettyTablexle1 = []xle2 = []url = f"http://api.openweathermap.org/data/2.5/weather?q=Shumerlya&appid=7ca6e88e64dfaf8f825865c2e7b7a07a&units=metric"bet = urllib.request.urlopen(url)data = json.loads(bet.read().decode('utf-8'))table = PrettyTable()table.field_names = ["Координаты", "Погода", "Ветер","облака","Инфо"]table.add_row([data["coord"], data["weather"],data['wind'],data['clouds'],data['sys']])print(data)print(table)